#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""内嵌颜色编制表数据。

来源：用户提供的《颜色编制表.xlsx》ALL sheet。
生成规则：保留 Excel 原始行序；同体系同代码的第一行作为主映射。
数据使用 zlib+base64 压缩，避免运行时依赖外部 Excel。
"""
from __future__ import annotations

import base64
import json
import zlib

COLOR_MAPPING_SOURCE = "颜色编制表.xlsx/ALL"
COLOR_MAPPING_ROW_COUNT = 393

_COLOR_MAPPING_ZLIB_B64 = (
    ""
)

COLOR_MAPPING_ROWS: tuple[tuple[int, str, str, str, str, str], ...] = tuple(
    tuple(row)
    for row in json.loads(
        zlib.decompress(base64.b64decode(_COLOR_MAPPING_ZLIB_B64)).decode("utf-8")
    )
)

if len(COLOR_MAPPING_ROWS) != COLOR_MAPPING_ROW_COUNT:
    raise RuntimeError(
        f"内嵌颜色映射解码行数异常：expected={COLOR_MAPPING_ROW_COUNT}, "
        f"actual={len(COLOR_MAPPING_ROWS)}"
    )
